import { useState } from "react";
import classes from "./ChatInput.module.css";

const ChatInput = () => {
  const [enteredValue, setEnteredValue] = useState("");

  const isEmpty = true;
  if (enteredValue !== "") {
    isEmpty = false;
  }

  const onSubmitHandler = () => {
    console.log(enteredValue);
    document.getElementById("chatbox").innerHTML = "";
    setEnteredValue("");
  };

  const onKeydownHandler = (event) => {
    if (event.key === "Enter" && !event.shiftKey) {
      event.preventDefault();
      onSubmitHandler();
      return;
    } else {
      setEnteredValue(event.currentTarget.textContent);
    }
  };

  const onInputHandler = (event) => {
    setEnteredValue(event.currentTarget.textContent);
  };

  const onPasteHandler = (event) => {
    event.preventDefault();
  };

  return (
    <form id="chat-form" className={classes["form"]}>
      <div className={classes["container"]}>
        {/* <div className={classes["attach"]}>+</div> */}
        <div className={classes["text-area"]}>
          <div className={classes["textbox"]}>
            {!isEmpty && (
              <div
                className={`${classes["placeholder"]} ${classes["text-padding"]}`}
              >
                Message
              </div>
            )}
            <div
              className={`${classes["text"]} ${classes["text-padding"]}`}
              id="chatbox"
              role="textbox"
              contentEditable="true"
              aria-multiline="true"
              spellCheck="true"
              onKeyDown={onKeydownHandler}
              onInput={onInputHandler}
              // onPaste={onPasteHandler}
            ></div>
          </div>
        </div>
      </div>
    </form>
  );
};

export default ChatInput;
